usecase.code:
@startuml
left to right direction
actor Developer
rectangle DiagramPreview {
  Developer -- (Preview PlantUML)
  Developer -- (Export SVG)
}
@enduml

activity.code:
@startuml
start
:Paste source;
if (Valid?) then (yes)
  :Render preview;
else (no)
  :Show error;
endif
stop
@enduml

